usort( $cron_jobs, function ($a, $b) use ($sort_col, $sort_dir) {

			$val_a = $a->$sort_col;
			$val_b = $b->$sort_col;

			// Handle different data types
			if ( is_numeric( $val_a ) && is_numeric( $val_b ) ) {
				$result = $val_a <=> $val_b;
			} else {
				$result = strcasecmp( (string) $val_a, (string) $val_b );
			}

			return $sort_dir === 'DESC' ? -$result : $result;
		} )

